import{_ as t,W as e,X as d,a1 as r}from"./framework-c9619a7b.js";const a={},o=r('<h1 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h1><p>特点：</p><ol><li>xx</li><li>xx</li><li>xx</li></ol><h1 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h1><blockquote><p>背景：由于Dendron很多功能都没有设置快捷键，使用起来不是很方便，但是可以自己为其指定快捷键。VSCode中指定快捷键的方式可以参考： ![[快捷键设置|Tutorial.VSCode使用教程#查看修改新建删除快捷键]]</p></blockquote><h2 id="基础" tabindex="-1"><a class="header-anchor" href="#基础" aria-hidden="true">#</a> 基础</h2><h3 id="note管理" tabindex="-1"><a class="header-anchor" href="#note管理" aria-hidden="true">#</a> note管理</h3><table><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+L</code></td><td>创建/查找note</td></tr><tr><td><code>Ctrl+K Ctrl+Shift+X</code></td><td>重命名note</td></tr><tr><td><code>Ctrl+Shift+D</code></td><td>删除当前note</td></tr><tr><td><code>Ctrl+K Shift+Alt+R</code></td><td>Refactor Hierachy, 把所有文件名中匹配到的部分替换为其他</td></tr><tr><td><code>Ctrl+K Ctrl+Shift+H</code></td><td>Move Header, 把当前note光标下的标题移动到其他note尾部</td></tr><tr><td><code>Ctrl+K Ctrl+Shift+S</code></td><td>Move Selection, 把当前note鼠标选中的部分移动到其他note尾部</td></tr><tr><td><code>Ctrl+K Ctrl+Shift+T</code></td><td>Apply Template, 在当前note中应用模板</td></tr><tr><td><code>Ctrl+K Ctrl+Enter</code></td><td>Go to Note, 跳转到目标note，没有会自动新建</td></tr></tbody></table><p>当创建很长名字的note时，可以先在文档中编辑好，然后光标放在名称上，然后使用<code>Dendron: Go to Note</code>会自动创建。</p><h3 id="link管理" tabindex="-1"><a class="header-anchor" href="#link管理" aria-hidden="true">#</a> link管理</h3><table><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+Shift+C</code></td><td>获取当前激活note的link，插入后只会显示一个超链接。如果在标题处使用则会生成直接指向目标标题的链接</td></tr><tr><td><code>Ctrl+Shift+R</code></td><td>获取当前激活note的reference，插入后会在当前页面显示目标页面</td></tr></tbody></table><ol><li><p>获取note部分内容的link</p></li><li><p>引用note</p></li><li><p>部分引用note</p></li></ol><h2 id="schema管理" tabindex="-1"><a class="header-anchor" href="#schema管理" aria-hidden="true">#</a> schema管理</h2><h2 id="模板" tabindex="-1"><a class="header-anchor" href="#模板" aria-hidden="true">#</a> 模板</h2><h1 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h1>',15),h=[o];function n(i,l){return e(),d("div",null,h)}const s=t(a,[["render",n],["__file","Dendron个人知识库工具使用教程.html.vue"]]);export{s as default};
